import 'package:flutter/material.dart';
import '../core/app_theme.dart';
import '../widgets/app_widgets.dart';

class NotificationPage extends StatelessWidget { const NotificationPage({super.key}); @override Widget build(BuildContext context) => FormScaffold(title: 'Notifikasi', subtitle: '', child: Column(children: [const Row(children: [Expanded(child: _Filter('Semua', true)), SizedBox(width: 8), Expanded(child: _Filter('7 Hari', false)), SizedBox(width: 8), Expanded(child: _Filter('1 Bulan', false))]), const SizedBox(height: 16), ...const [('Pengajuan Sedang Diverifikasi', 'Pengajuan Anda sedang dalam proses pemeriksaan oleh admin.', '15 April, 10.20 WIB'), ('Pengajuan Ditolak', 'Pengajuan Anda ditolak. Silakan lihat detail pengajuan untuk mengetahui alasan penolakan.', '15 April, 10.20 WIB'), ('Pengumuman Baru', 'Terdapat informasi terbaru terkait layanan pensiun. Klik untuk melihat detail pengumuman.', '12 April, 10.20 WIB'), ('Profil Berhasil Diperbarui', 'Data profil Anda telah berhasil disimpan. Pastikan informasi yang diberikan sudah sesuai dan benar.', '08 April, 10.20 WIB')].map((item) => _NotificationCard(title: item.$1, body: item.$2, date: item.$3))])); }
class _Filter extends StatelessWidget { const _Filter(this.label, this.selected); final String label; final bool selected; @override Widget build(BuildContext context) => OutlinedButton(onPressed: () {}, style: OutlinedButton.styleFrom(backgroundColor: selected ? alpenBlue : Colors.white, foregroundColor: selected ? Colors.white : Colors.black, side: BorderSide(color: selected ? alpenBlue : const Color(0xFFD0D5DD))), child: Text(label)); }
class _NotificationCard extends StatelessWidget { const _NotificationCard({required this.title, required this.body, required this.date}); final String title, body, date; @override Widget build(BuildContext context) => Container(width: double.infinity, margin: const EdgeInsets.only(bottom: 16), padding: const EdgeInsets.all(12), decoration: BoxDecoration(border: Border.all(color: const Color(0xFFD0D5DD)), borderRadius: BorderRadius.circular(8)), child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text(title, style: const TextStyle(fontWeight: FontWeight.w800)), const SizedBox(height: 8), Text(body, style: const TextStyle(color: Color(0xFF667085))), const SizedBox(height: 8), Text(date, style: const TextStyle(color: Color(0xFF667085), fontSize: 11))])); }
